def classify(name, code):
    for kw, ind in IND_KEYWORDS:
        if kw in name:
            return ind
    if code.startswith('688'): return 'AI芯片'
    if code.startswith('30'): return '创业板'
    return '工业制造'

def make_entry(code, name):
    ind = classify(name, code)
    region = "中国"
    if '江苏' in name: region = "江苏"
    elif '南京' in name: region = "南京"
    elif '上海' in name: region = "上海"
    elif '宁波' in name: region = "宁波/长三角"
    elif '北京' in name: region = "北京"
    elif '广东' in name or '广州' in name or '深圳' in name: region = "广东/大湾区"
    elif '浙江' in name or '杭州' in name: region = "浙江"
    elif '山东' in name: region = "山东"
    elif '福建' in name: region = "福建"
    elif '安徽' in name: region = "安徽"
    elif '湖北' in name or '武汉' in name: region = "湖北"
    elif '四川' in name or '成都' in name: region = "四川"
    elif '湖南' in name: region = "湖南"
    elif '河南' in name: region = "河南"
    elif '陕西' in name: region = "陕西"
    elif '重庆' in name: region = "重庆"
    
    gen = GEN_MAP.get(ind)
    if gen is None:
        return generic(name, ind)
    if gen in (bank, broker):
        return gen(name, region)
    return gen(name)

# 生成所有条目
NEW = {}
for code, name, mcap in uncovered:
    if code not in NEW:
        NEW[code] = make_entry(code, name)

